import{_ as i,o as e,c as a,a as n}from"./chunks/framework.8tiMeCK-.js";const k=JSON.parse('{"title":"第 11 章  深入内核：当调试器成为内核的一部分","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch11_1.md","filePath":"notes/linux_kernel_debugging/ch11_1.md","lastUpdated":null}'),t={name:"notes/linux_kernel_debugging/ch11_1.md"};function p(l,s,d,h,r,o){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="第-11-章-深入内核-当调试器成为内核的一部分" tabindex="-1">第 11 章 深入内核：当调试器成为内核的一部分 <a class="header-anchor" href="#第-11-章-深入内核-当调试器成为内核的一部分" aria-label="Permalink to &quot;第 11 章  深入内核：当调试器成为内核的一部分&quot;">​</a></h1><p>有一类问题，普通调试器是碰不到的。</p><p>当你的代码在 Ring 0 运行，当 <code>printk</code> 的输出缓冲区因为系统崩溃而无法刷新，当你要调试的是一个中断处理程序——这时候，普通的用户态调试工具不仅软弱无力，甚至根本不存在。</p><p>本章的任务，就是构建一种更底层的调试能力。我们将不再从外部观察进程，而是让调试器本身成为内核的一部分。</p><p>这不是「学会使用一个工具」那么简单。理解 KGDB，意味着你开始理解操作系统的上帝视角——能够暂停整个世界，查看它的状态，然后让时间继续流动。</p><hr><h2 id="_11-1-技术准备" tabindex="-1">11.1 技术准备 <a class="header-anchor" href="#_11-1-技术准备" aria-label="Permalink to &quot;11.1  技术准备&quot;">​</a></h2><p>在深入内核之前，我们需要先把场地清理干净。</p><p>本章的基础工作空间和工具链依然沿袭我们在第 1 章建立的规范——如果你还没搭建那个环境，现在是个回头补课的好时机。所有的代码示例都已经躺在书里的 GitHub 仓库上了，随用随取。</p><p>但这一次，我们要玩的东西有点大。除了常规的武器，我们需要安装更重型的模拟器组件，以及一个准备好的根文件系统镜像。</p><p>这一步虽然繁琐，但别偷懒。地基如果不打牢，后面内核一崩，你连问题出在哪个环上都找不到。</p><h3 id="_1-安装-qemu-和依赖库" tabindex="-1">1. 安装 QEMU 和依赖库 <a class="header-anchor" href="#_1-安装-qemu-和依赖库" aria-label="Permalink to &quot;1. 安装 QEMU 和依赖库&quot;">​</a></h3><p>我们需要 QEMU 的 ARM 和 x86 版本，这不仅仅是跑两个虚拟机那么简单——本章我们将大量依赖 QEMU 的调试特性。</p><p>打开终端，执行以下命令。这一连串包下来大概要吃掉你 400 MB 的磁盘空间：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-arm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> qemu-system-x86</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lzop</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">libncursesw5 </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">libncursesw5-dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> p7zip-full</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这里解释一下几个关键角色：</p><ul><li><code>qemu-system-arm</code> 和 <code>qemu-system-x86</code>：这是我们的「沙盒」。KGDB 调试通常需要两台机器，或者用虚拟机充当目标机。QEMU 完美扮演了这个倒霉的目标机角色，而且它对 GDB 的支持做得极好。</li><li><code>lzop</code>：一个压缩工具，内核世界里有时候你会遇到 <code>.lzo</code> 格式的东西。</li><li><code>libncursesw5</code>：如果你要配置内核（<code>make menuconfig</code>），没有这个库你的菜单界面弹不出来。</li><li><code>p7zip-full</code>：一会儿解压根文件系统要用，别问为什么不用 <code>unzip</code>，有些事情就是这么任性。</li></ul><h3 id="_2-获取根文件系统镜像" tabindex="-1">2. 获取根文件系统镜像 <a class="header-anchor" href="#_2-获取根文件系统镜像" aria-label="Permalink to &quot;2. 获取根文件系统镜像&quot;">​</a></h3><p>接下来，我们需要一个现成的 ARM Linux 根文件系统。</p><p>这个文件后面我们调试内核模块时会用到。请导航到本书源码的 <code>ch11/</code> 目录，然后下载这个大块头（大约 178 MB，喝杯咖啡慢慢等）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">book_sr</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">c</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch11</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/PacktPublishing/Linux-Kernel-Debugging/raw/main/ch11/rootfs_deb.img.7z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>⚠️ <strong>注意——这里有个小坑</strong></p><p>如果你直接运行上面的 <code>wget</code>，GitHub 可能会耍点小脾气。由于仓库里已经存在一个占位用的 <code>rootfs_deb.img.7z</code>（meta 文件），<code>wget</code> 为了不覆盖它，会把你下载下来的真实文件重命名为 <code>rootfs_deb.img.7z.1</code>。</p><p>这名字不对，后续脚本会找不到它。你需要手动修正一下这个「笔误」：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rootfs_deb.img.7z</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rootfs_deb.img.7z.1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rootfs_deb.img.7z</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>现在的目录结构应该干净利落了（如果你好奇，可以翻到后面的图 11.8 看看最终长什么样，但现在我们先把文件放在这，后面用到时再解压）。</p><h3 id="_3-关于-gdb-的前置知识" tabindex="-1">3. 关于 GDB 的前置知识 <a class="header-anchor" href="#_3-关于-gdb-的前置知识" aria-label="Permalink to &quot;3. 关于 GDB 的前置知识&quot;">​</a></h3><p>最后一件事：我们在这一章会大量使用 GDB。</p><p>我会假设你已经不是一个 GDB 小白了——比如知道 <code>break</code>、<code>run</code>、<code>next</code>、<code>continue</code> 是干什么的。如果你现在脑子里只有 <code>printf</code> 调试法，建议先去搜一个「GDB cheat sheet」快速扫一眼。</p><p>但别担心，内核调试和用户态调试还是有点区别的，那些真正酷炫（且危险）的操作，我们会一步一步带着你做。</p><p>场地清理完毕。接下来，我们要把调试器这个外挂，正式植入到内核里去了。</p>`,31)])])}const u=i(t,[["render",p]]);export{k as __pageData,u as default};
